function useFirebaseState(path, initialValue, seedIfEmpty) {
    const [state, setState] = useState(initialValue);
    const [synced, setSynced] = useState(false);
    useEffect(() => {
        if (!window.firebaseDb) {
            setSynced(false);
            return;
        }
        const ref = window.firebaseDb.ref(path);
        const listener = ref.on("value", (snap) => {
            const val = snap.val();
            if (val === null || val === undefined) {
                if (seedIfEmpty !== undefined)
                    ref.set(seedIfEmpty);
                setState(initialValue);
            }
            else {
                setState(val);
            }
            setSynced(true);
        }, (err) => { console.error("Firebase read error:", path, err); setSynced(false); });
        return () => ref.off("value", listener);
    }, [path]);
    const update = (newVal) => {
        const resolved = typeof newVal === "function" ? newVal(state) : newVal;
        setState(resolved);
        if (window.firebaseDb) {
            window.firebaseDb.ref(path).set(resolved === undefined ? null : resolved).catch((e) => console.error("Firebase write error:", path, e));
        }
    };
    return [state, update, synced];
}
